--
-- Table structure for table `sensor_weather_data`
--

DROP TABLE IF EXISTS `sensor_weather_data`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sensor_weather_data` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `sesi_id_getdata` int NOT NULL,
  `node_id` int NOT NULL,
  `voltage` decimal(5,2) DEFAULT NULL COMMENT 'Voltage in V',
  `current` decimal(7,2) DEFAULT NULL COMMENT 'Current in mA',
  `power` decimal(8,2) DEFAULT NULL COMMENT 'Power in mW',
  `light` decimal(10,2) DEFAULT NULL COMMENT 'Light intensity in lux',
  `rain` decimal(7,2) DEFAULT NULL COMMENT 'Rain percentage',
  `rain_adc` int DEFAULT NULL COMMENT 'Rain sensor ADC value',
  `wind` decimal(7,2) DEFAULT NULL COMMENT 'Wind speed',
  `wind_pulse` int DEFAULT NULL COMMENT 'Wind pulse count',
  `humidity` decimal(5,2) DEFAULT NULL COMMENT 'Humidity in %',
  `temp_dht` decimal(5,2) DEFAULT NULL COMMENT 'Temperature from DHT in °C',
  `ts_counter` int DEFAULT NULL COMMENT 'Timestamp counter',
  `received_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_sesi_id` (`sesi_id_getdata`),
  KEY `idx_node_id` (`node_id`),
  KEY `idx_received_at` (`received_at`),
  KEY `idx_composite` (`sesi_id_getdata`,`node_id`),
  KEY `idx_weather_conditions` (`temp_dht`,`humidity`,`rain_adc`),
  KEY `sensor_weather_data_received_at_index` (`received_at`),
  KEY `sensor_weather_data_node_id_index` (`node_id`)
) ENGINE=InnoDB AUTO_INCREMENT=118 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

